package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            // We override readLine to call super.readLine() from BufferedReader
            @Override
            public String readLine() throws IOException {
                return super.readLine();
            }
        };
    }

    @Test
    void testReadLine_withNonEmptyLine() throws Exception {
        ExtendedBufferedReader spyReader = spy(new ExtendedBufferedReader(mockReader));
        // Mock super.readLine() to return a non-empty string
        doReturn("Hello World").when(spyReader).readLine();

        String result = spyReader.readLine();

        assertEquals("Hello World", result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = lastCharField.getInt(spyReader);
        assertEquals('d', lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = lineCounterField.getInt(spyReader);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadLine_withEmptyLine() throws Exception {
        ExtendedBufferedReader spyReader = spy(new ExtendedBufferedReader(mockReader));
        // Mock super.readLine() to return an empty string
        doReturn("").when(spyReader).readLine();

        String result = spyReader.readLine();

        assertEquals("", result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = lastCharField.getInt(spyReader);
        // lastChar should remain UNDEFINED because line length is 0
        assertEquals(ExtendedBufferedReader.UNDEFINED, lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = lineCounterField.getInt(spyReader);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadLine_withNullLine() throws Exception {
        ExtendedBufferedReader spyReader = spy(new ExtendedBufferedReader(mockReader));
        // Mock super.readLine() to return null
        doReturn(null).when(spyReader).readLine();

        String result = spyReader.readLine();

        assertNull(result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = lastCharField.getInt(spyReader);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = lineCounterField.getInt(spyReader);
        // lineCounter should remain 0 because line was null
        assertEquals(0, lineCounter);
    }
}
